import { McpServer } from '@modelcontextprotocol/sdk/server/mcp.js';
import { StdioServerTransport } from '@modelcontextprotocol/sdk/server/stdio.js';
import { dirname } from 'path';
import { z } from 'zod';
import type { AgentVaultCommandEnvironment, AgentVaultCommandIO } from './core/note-generators';
import {
  handleCreatePhaseCommand,
  handleCreateStepCommand,
  handleCreateSessionCommand,
  handleCreateBugCommand,
  handleCreateDecisionCommand,
  handleUpdateFrontmatterCommand,
  handleAppendSectionCommand,
  handleRebuildIndexesCommand,
  handleRefreshActiveContextCommand,
  handleRefreshAllHomeNotesCommand,
} from './core/note-generators';
import {
  handleValidateFrontmatterCommand,
  handleValidateNoteStructureCommand,
  handleValidateRequiredLinksCommand,
  handleDetectOrphansCommand,
  handleValidateAllCommand,
  handleVaultDoctorCommand,
} from './core/note-validators';
import { formatCommandCatalog, formatCommandHelp } from './core/command-catalog';
import { formatCodeGraphLookupResultsAsToon, loadCodeGraphIndex, queryCodeGraphIndex } from './core/code-graph-lookup';
import { formatInitResultAsToon, formatScanResultAsToon, formatVaultConfigAsToon } from './core/mcp-response-format';
import {
  ensureVaultGraph,
  formatVaultTraverseResultAsJson,
  formatVaultTraverseResultAsToon,
  invalidateVaultGraphCache,
  traverseVaultGraph,
} from './core/vault-graph';
import { readVaultConfig, updateVaultConfig } from './core/vault-config';
import { extractVaultNoteTarget } from './core/vault-extract';
import { isProjectVault, resolveVaultRoot } from './core/vault-files';
import { initVault } from './scaffold/init';
import { scanProject } from './scaffold/scan';
import { writeCodeGraph } from './scaffold/code-graph';
import { generateStubs, initializeStubCache } from './scaffold/code-stubs';

type CommandHandler = (argv: string[], environment?: AgentVaultCommandEnvironment) => Promise<number>;

const captureOutput = async (handler: CommandHandler, argv: string[], vaultRoot: string) => {
  const stdout: string[] = [];
  const stderr: string[] = [];
  const io: AgentVaultCommandIO = {
    stdout: (msg) => stdout.push(msg),
    stderr: (msg) => stderr.push(msg),
  };
  const exitCode = await handler(argv, { vaultRoot, io });
  const output = [...stdout, ...stderr].join('\n');
  return {
    content: [{ type: 'text' as const, text: output || (exitCode === 0 ? 'OK' : 'Command failed') }],
    isError: exitCode !== 0,
  };
};

const noArgs = (handler: CommandHandler) => captureOutput(handler, [], resolveVaultRoot(process.cwd()));

export async function startServer(): Promise<void> {
  const server = new McpServer({ name: 'agent-vault', version: '0.0.1' });

  // ── vault_init ──────────────────────────────────────────────────────
  server.tool(
    'vault_init',
    'Initialize `.agent-vault/`, scan the project, and backfill from `.planning/` when present.',
    { project_root: z.string().optional().describe('Project root. Defaults to cwd.') },
    async ({ project_root }) => {
      const root = project_root || process.cwd();
      const result = await initVault(root);
      const config = await readVaultConfig(result.vaultRoot);
      return {
        content: [{
          type: 'text',
          text: formatInitResultAsToon(result, config),
        }],
      };
    },
  );

  // ── vault_scan ──────────────────────────────────────────────────────
  server.tool(
    'vault_scan',
    'Scan the project and return compact metadata such as languages, frameworks, package manager, key paths, tests, build, CI, and entry points.',
    { project_root: z.string().optional().describe('Project root. Defaults to cwd.') },
    async ({ project_root }) => {
      const result = await scanProject(project_root || process.cwd());
      return { content: [{ type: 'text', text: formatScanResultAsToon(result) }] };
    },
  );

  // ── vault_create ────────────────────────────────────────────────────
  server.tool(
    'vault_create',
    'Create a phase, step, session, bug, or decision note.',
    {
      type: z.enum(['phase', 'step', 'session', 'bug', 'decision']).describe('Note type to create'),
      title: z.string().optional().describe('Note title (required for phase, step, bug, decision)'),
      phase_number: z.string().optional().describe('Phase number (step: required; phase: optional, auto-generated)'),
      step_number: z.string().optional().describe('Step number (required for step)'),
      previous: z.string().optional().describe('Previous phase ID for linkage (phase only)'),
      insert_before: z.string().optional().describe('Insert before this phase, shifting existing phases forward (phase only)'),
      related_step: z.string().optional().describe('Step ID to link (required for session)'),
      agent: z.string().optional().describe('Agent name (session only)'),
      bug_id: z.string().optional().describe('Bug ID, auto-generated if omitted (bug only)'),
      decision_id: z.string().optional().describe('Decision ID, auto-generated if omitted (decision only)'),
      phase: z.string().optional().describe('Related phase ID (decision only)'),
      session: z.string().optional().describe('Related session ID (bug, decision)'),
      bug: z.string().optional().describe('Related bug ID (decision only)'),
      step: z.string().optional().describe('Related step ID (bug only)'),
    },
    async (input) => {
      const vaultRoot = resolveVaultRoot(process.cwd());

      switch (input.type) {
        case 'phase': {
          if (!input.title) return { content: [{ type: 'text', text: 'title is required for phase' }], isError: true };
          const argv = [input.title];
          if (input.phase_number) argv.push('--phase-number', input.phase_number);
          if (input.previous) argv.push('--previous', input.previous);
          if (input.insert_before) argv.push('--insert-before', input.insert_before);
          return captureOutput(handleCreatePhaseCommand, argv, vaultRoot);
        }

        case 'step': {
          if (!input.phase_number || !input.step_number || !input.title) {
            return { content: [{ type: 'text', text: 'phase_number, step_number, and title are required for step' }], isError: true };
          }
          return captureOutput(handleCreateStepCommand, [input.phase_number, input.step_number, input.title], vaultRoot);
        }

        case 'session': {
          if (!input.related_step) return { content: [{ type: 'text', text: 'related_step is required for session' }], isError: true };
          const argv = [input.related_step];
          if (input.agent) argv.push('--agent', input.agent);
          return captureOutput(handleCreateSessionCommand, argv, vaultRoot);
        }

        case 'bug': {
          if (!input.title) return { content: [{ type: 'text', text: 'title is required for bug' }], isError: true };
          const argv = [input.title];
          if (input.bug_id) argv.push('--bug-id', input.bug_id);
          if (input.step) argv.push('--step', input.step);
          if (input.session) argv.push('--session', input.session);
          return captureOutput(handleCreateBugCommand, argv, vaultRoot);
        }

        case 'decision': {
          if (!input.title) return { content: [{ type: 'text', text: 'title is required for decision' }], isError: true };
          const argv = [input.title];
          if (input.decision_id) argv.push('--decision-id', input.decision_id);
          if (input.phase) argv.push('--phase', input.phase);
          if (input.session) argv.push('--session', input.session);
          if (input.bug) argv.push('--bug', input.bug);
          return captureOutput(handleCreateDecisionCommand, argv, vaultRoot);
        }
      }
    },
  );

  // ── vault_traverse ──────────────────────────────────────────────────
  server.tool(
    'vault_traverse',
    'Load linked vault context from a root note. TOON is the default compact format.',
    {
      root: z.string().describe('Root note path or wikilink target.'),
      depth: z.number().int().min(0).max(10).describe('Traversal depth.'),
      direction: z.enum(['outgoing', 'incoming', 'both']).default('outgoing').describe('Link direction.'),
      format: z.enum(['toon', 'json']).default('toon').describe('Output format.'),
      include_content: z.boolean().default(false).describe('Include bounded content excerpts.'),
      note_type: z.array(z.string()).optional().describe('Optional note_type filter.'),
      status: z.array(z.string()).optional().describe('Optional status filter.'),
      max_notes: z.number().int().min(1).max(5000).default(500).describe('Max notes returned.'),
      resolver: z.enum(['filesystem', 'obsidian']).optional().describe('Resolver override.'),
    },
    async ({ root, depth, direction, format, include_content, note_type, status, max_notes, resolver }) => {
      const vaultRoot = resolveVaultRoot(process.cwd());
      const config = await readVaultConfig(vaultRoot);
      const effectiveResolver = resolver ?? config.resolver;
      const { graph, warnings } = await ensureVaultGraph(vaultRoot, effectiveResolver);
      const result = traverseVaultGraph(graph, {
        root,
        depth,
        direction,
        includeContent: include_content,
        noteTypes: note_type,
        statuses: status,
        maxNotes: max_notes,
        resolver: effectiveResolver,
      }, warnings);

      const text = format === 'json'
        ? formatVaultTraverseResultAsJson(result)
        : formatVaultTraverseResultAsToon(result);

      return { content: [{ type: 'text', text }] };
    },
  );

  // ── vault_extract ──────────────────────────────────────────────────
  server.tool(
    'vault_extract',
    'Extract a bounded note section by markdown heading or generated block without returning the full note.',
    {
      note_path: z.string().describe('Vault-relative note path. .md is optional.'),
      heading: z.string().optional().describe('Exact markdown heading text to extract, excluding # markers.'),
      block: z.string().optional().describe('Generated block name to extract, e.g. phase-steps.'),
      include_markers: z.boolean().default(true).describe('For block extraction, include AGENT-START/END markers.'),
    },
    async ({ note_path, heading, block, include_markers }) => {
      try {
        const vaultRoot = resolveVaultRoot(process.cwd());
        const result = await extractVaultNoteTarget(vaultRoot, {
          notePath: note_path,
          heading,
          block,
          includeMarkers: include_markers,
        });
        return {
          content: [{
            type: 'text',
            text: [
              `notePath: ${result.notePath}`,
              `selector: ${result.selector}`,
              'content: |',
              ...result.content.split('\n').map((line) => `  ${line}`),
            ].join('\n'),
          }],
        };
      } catch (err) {
        return {
          isError: true,
          content: [{
            type: 'text',
            text: `Failed to extract vault note target: ${err instanceof Error ? err.message : String(err)}`,
          }],
        };
      }
    },
  );

  // ── vault_lookup_code_graph ───────────────────────────────────────
  server.tool(
    'vault_lookup_code_graph',
    'Search the compact code-graph index for matching symbols and files. Returns TOON; compact mode is the default.',
    {
      query: z.string().describe('Case-insensitive symbol substring.'),
      limit: z.number().int().min(1).max(200).default(10).describe('Max matches.'),
      path_substring: z.string().optional().describe('Optional file-path filter.'),
      exported_only: z.boolean().default(false).describe('Only exported/public symbols.'),
      compact: z.boolean().default(true).describe('Use grouped compact TOON output.'),
    },
    async ({ query, limit, path_substring, exported_only, compact }) => {
      try {
        const vaultRoot = resolveVaultRoot(process.cwd());
        const index = await loadCodeGraphIndex(vaultRoot);
        const matches = queryCodeGraphIndex(index, {
          query,
          limit,
          pathSubstring: path_substring,
          exportedOnly: exported_only,
        });
        return {
          content: [{
            type: 'text',
            text: formatCodeGraphLookupResultsAsToon(index, matches, query, { compact }),
          }],
        };
      } catch (err) {
        return {
          isError: true,
          content: [{
            type: 'text',
            text: `Failed to query code graph index: ${err instanceof Error ? err.message : String(err)}`,
          }],
        };
      }
    },
  );

  // ── vault_mutate ────────────────────────────────────────────────────
  server.tool(
    'vault_mutate',
    'Safely update note frontmatter or append to a named section.',
    {
      action: z.enum(['update_frontmatter', 'append_section']).describe('Mutation action.'),
      note_path: z.string().describe('Path relative to vault root.'),
      updates: z.record(z.string(), z.string()).optional().describe('Fields to set.'),
      heading: z.string().optional().describe('Target heading.'),
      content: z.string().optional().describe('Content to append.'),
    },
    async (input) => {
      const vaultRoot = resolveVaultRoot(process.cwd());

      switch (input.action) {
        case 'update_frontmatter': {
          if (!input.updates || Object.keys(input.updates).length === 0) {
            return { content: [{ type: 'text', text: 'updates is required for update_frontmatter' }], isError: true };
          }
          const argv = [input.note_path];
          for (const [key, value] of Object.entries(input.updates)) {
            argv.push('--set', `${key}=${value}`);
          }
          const result = await captureOutput(handleUpdateFrontmatterCommand, argv, vaultRoot);
          invalidateVaultGraphCache(vaultRoot);
          return result;
        }

        case 'append_section': {
          if (!input.heading || !input.content) {
            return { content: [{ type: 'text', text: 'heading and content are required for append_section' }], isError: true };
          }
          const result = await captureOutput(
            handleAppendSectionCommand,
            [input.note_path, '--heading', input.heading, '--content', input.content],
            vaultRoot,
          );
          invalidateVaultGraphCache(vaultRoot);
          return result;
        }
      }
    },
  );

  // ── vault_refresh ───────────────────────────────────────────────────
  server.tool(
    'vault_refresh',
    'Refresh generated indexes, active context, or the code graph.',
    {
      target: z.enum(['all', 'indexes', 'active_context', 'code_graph', 'code_stubs']).default('all').describe('Refresh target.'),
    },
    async ({ target }) => {
      switch (target) {
        case 'all': return noArgs(handleRefreshAllHomeNotesCommand);
        case 'indexes': return noArgs(handleRebuildIndexesCommand);
        case 'active_context': return noArgs(handleRefreshActiveContextCommand);
        case 'code_graph': {
          try {
            const vaultRoot = resolveVaultRoot(process.cwd());
            if (!isProjectVault(vaultRoot)) {
              return {
                isError: true,
                content: [{
                  type: 'text',
                  text: `No project vault found. Resolved ${vaultRoot} is not a vault created by vault_init. Run vault_init first.`,
                }],
              };
            }
            const projectRoot = dirname(vaultRoot);
            const scan = await scanProject(projectRoot);
            const graph = await writeCodeGraph(projectRoot, vaultRoot, scan.repoName);
            return {
              content: [{
                type: 'text',
                text: `Code graph refreshed: ${graph.totalFiles} files, ${graph.totalSymbols} symbols indexed.`,
              }],
            };
          } catch (err) {
            return {
              isError: true,
              content: [{
                type: 'text',
                text: `Failed to refresh code graph: ${err instanceof Error ? err.message : String(err)}`,
              }],
            };
          }
        }

        case 'code_stubs': {
          try {
            const vaultRoot = resolveVaultRoot(process.cwd());
            if (!isProjectVault(vaultRoot)) {
              return {
                isError: true,
                content: [{
                  type: 'text',
                  text: `No project vault found. Resolved ${vaultRoot} is not a vault created by vault_init. Run vault_init first.`,
                }],
              };
            }
            const projectRoot = dirname(vaultRoot);
            // Initialize the stub cache directory and manifest
            await initializeStubCache(vaultRoot);
            return {
              content: [{
                type: 'text',
                text: 'Code stubs cache initialized. Stubs are generated on-demand by the context compiler.',
              }],
            };
          } catch (err) {
            return {
              isError: true,
              content: [{
                type: 'text',
                text: `Failed to initialize stub cache: ${err instanceof Error ? err.message : String(err)}`,
              }],
            };
          }
        }
      }
    },
  );

  // ── vault_validate ──────────────────────────────────────────────────
  server.tool(
    'vault_validate',
    'Run read-only vault validation checks or a strict doctor report.',
    {
      target: z.enum(['all', 'frontmatter', 'structure', 'links', 'orphans', 'doctor']).default('all').describe('Validation target.'),
    },
    async ({ target }) => {
      switch (target) {
        case 'all': return noArgs(handleValidateAllCommand);
        case 'frontmatter': return noArgs(handleValidateFrontmatterCommand);
        case 'structure': return noArgs(handleValidateNoteStructureCommand);
        case 'links': return noArgs(handleValidateRequiredLinksCommand);
        case 'orphans': return noArgs(handleDetectOrphansCommand);
        case 'doctor': return noArgs(handleVaultDoctorCommand);
      }
    },
  );

  // ── vault_config ────────────────────────────────────────────────────
  server.tool(
    'vault_config',
    'View or update `.agent-vault/.config.json`.',
    {
      resolver: z.enum(['filesystem', 'obsidian']).optional().describe('Default link resolver.'),
    },
    async ({ resolver }) => {
      const vaultRoot = resolveVaultRoot(process.cwd());
      if (resolver) {
        const config = await updateVaultConfig(vaultRoot, { resolver });
        return { content: [{ type: 'text', text: formatVaultConfigAsToon(config) }] };
      }
      const config = await readVaultConfig(vaultRoot);
      return { content: [{ type: 'text', text: formatVaultConfigAsToon(config) }] };
    },
  );

  // ── vault_help ──────────────────────────────────────────────────────
  server.tool(
    'vault_help',
    'List commands or show help for one command.',
    { command: z.string().optional().describe('Command name.') },
    async ({ command }) => {
      try {
        const text = command
          ? formatCommandHelp(command as Parameters<typeof formatCommandHelp>[0])
          : formatCommandCatalog();
        return { content: [{ type: 'text', text }] };
      } catch (error) {
        return {
          isError: true,
          content: [{
            type: 'text',
            text: error instanceof Error ? error.message : String(error),
          }],
        };
      }
    },
  );

  const transport = new StdioServerTransport();
  await server.connect(transport);
}

import { execFile as execFileCallback } from 'child_process';
import { createHash } from 'crypto';
import { encode } from '@toon-format/toon';
import { basename, dirname, join } from 'path';
import { promisify } from 'util';
import { parseYamlFrontmatter } from './note-mutations';
import { readUtf8File, scanVaultMarkdownFiles, type VaultFileRecord } from './vault-files';

const execFile = promisify(execFileCallback);

const WIKI_LINK_PATTERN = /\[\[([^\]]+)\]\]/g;
const MARKDOWN_LINK_PATTERN = /\[[^\]]+\]\(([^)]+)\)/g;
const HEADING_PATTERN = /^( {0,3})#{1,6}[ \t]+(.+?)(?:[ \t]+#+[ \t]*)?[ \t]*$/m;
const ROOT_CONTENT_EXCERPT_LIMIT = 4000;
const CONTENT_EXCERPT_LIMIT = 2000;
const MIN_CONTENT_EXCERPT_LIMIT = 400;
const TOTAL_CONTENT_LIMIT = 24000;
const TRUNCATION_SUFFIX = '\n\n[truncated]';
const OBSIDIAN_TIMEOUT_MS = 5000;

export type VaultGraphResolver = 'filesystem' | 'obsidian';
export type VaultTraverseDirection = 'outgoing' | 'incoming' | 'both';

export interface VaultGraphNode {
  readonly absolutePath: string;
  readonly relativePath: string;
  readonly canonicalTarget: string;
  readonly title: string;
  readonly noteType?: string;
  readonly status?: string;
  readonly updated?: string;
  readonly mtimeMs: number;
  readonly frontmatter: Record<string, unknown>;
  readonly content: string;
  outgoingLinks: string[];
  incomingLinks: string[];
}

export interface VaultGraph {
  readonly vaultRoot: string;
  readonly resolver: VaultGraphResolver;
  readonly nodes: VaultGraphNode[];
  readonly nodesByCanonicalTarget: Map<string, VaultGraphNode>;
  readonly signature: string;
}

export interface VaultTraverseParams {
  readonly root: string;
  readonly depth: number;
  readonly direction: VaultTraverseDirection;
  readonly includeContent?: boolean;
  readonly noteTypes?: readonly string[];
  readonly statuses?: readonly string[];
  readonly maxNotes?: number;
  readonly resolver?: VaultGraphResolver;
}

export interface VaultTraverseResultNode {
  readonly path: string;
  readonly title: string;
  readonly noteType?: string;
  readonly status?: string;
  readonly updated?: string;
  readonly content?: string;
}

export interface VaultTraverseResultEdge {
  readonly from: string;
  readonly to: string;
}

export interface VaultTraverseResult {
  readonly meta: {
    readonly root: string;
    readonly depth: number;
    readonly direction: VaultTraverseDirection;
    readonly resolverRequested: VaultGraphResolver;
    readonly resolverUsed: VaultGraphResolver;
    readonly totalNotes: number;
    readonly truncated: boolean;
    readonly warnings: string[];
    readonly noteTypes?: readonly string[];
    readonly statuses?: readonly string[];
  };
  readonly notes: VaultTraverseResultNode[];
  readonly edges: VaultTraverseResultEdge[];
}

interface CachedVaultGraph {
  readonly signature: string;
  readonly graph: VaultGraph;
}

interface ParsedVaultNote {
  readonly absolutePath: string;
  readonly relativePath: string;
  readonly canonicalTarget: string;
  readonly mtimeMs: number;
  readonly content: string;
  readonly frontmatter: Record<string, unknown>;
  readonly title: string;
  readonly noteType?: string;
  readonly status?: string;
  readonly updated?: string;
}

const GRAPH_CACHE_MAX_SIZE = 4;
const graphCache = new Map<string, CachedVaultGraph>();

const setGraphCache = (key: string, value: CachedVaultGraph): void => {
  graphCache.delete(key);
  if (graphCache.size >= GRAPH_CACHE_MAX_SIZE) {
    const oldest = graphCache.keys().next().value;
    if (oldest !== undefined) {
      graphCache.delete(oldest);
    }
  }
  graphCache.set(key, value);
};

const normalizePathLikeValue = (value: string): string => value.replace(/\\/g, '/').replace(/\.md$/i, '');

const getCanonicalTarget = (relativePath: string): string => normalizePathLikeValue(relativePath);

const parseOptionalString = (value: unknown): string | undefined => {
  if (value instanceof Date && !Number.isNaN(value.getTime())) {
    return value.toISOString().slice(0, 10);
  }
  if (typeof value !== 'string') {
    return undefined;
  }
  const trimmed = value.trim();
  return trimmed.length > 0 ? trimmed : undefined;
};

const extractTitle = (content: string, frontmatter: Record<string, unknown>, relativePath: string): string => {
  const frontmatterTitle = parseOptionalString(frontmatter.title);
  if (frontmatterTitle) {
    return frontmatterTitle;
  }

  const headingMatch = HEADING_PATTERN.exec(content);
  if (headingMatch) {
    return headingMatch[2].trim();
  }

  return basename(relativePath, '.md');
};

const normalizeLinkTarget = (currentRelativePath: string, rawTarget: string): string | undefined => {
  const withoutAlias = rawTarget.split('|')[0]?.trim() ?? '';
  const withoutHeading = withoutAlias.split('#')[0]?.trim() ?? '';
  if (withoutHeading.length === 0) {
    return undefined;
  }

  if (withoutHeading.includes('<') || withoutHeading.includes('>')) {
    return undefined;
  }

  if (/^(?:https?:|mailto:|obsidian:|file:)/i.test(withoutHeading) || withoutHeading.startsWith('#')) {
    return undefined;
  }

  if (withoutHeading.startsWith('./') || withoutHeading.startsWith('../')) {
    return normalizePathLikeValue(join(dirname(currentRelativePath), withoutHeading));
  }

  return normalizePathLikeValue(withoutHeading);
};

export const collectLinks = (relativePath: string, content: string): ReadonlySet<string> => {
  const links = new Set<string>();
  const currentCanonicalTarget = getCanonicalTarget(relativePath);
  const addTarget = (rawTarget: string): void => {
    const normalized = normalizeLinkTarget(relativePath, rawTarget);
    if (!normalized || normalized === currentCanonicalTarget) {
      return;
    }
    links.add(normalized);
  };

  WIKI_LINK_PATTERN.lastIndex = 0;
  for (const match of content.matchAll(WIKI_LINK_PATTERN)) {
    addTarget(match[1]);
  }

  MARKDOWN_LINK_PATTERN.lastIndex = 0;
  for (const match of content.matchAll(MARKDOWN_LINK_PATTERN)) {
    addTarget(match[1]);
  }

  return links;
};

const loadParsedVaultNotes = async (files: readonly VaultFileRecord[]): Promise<ParsedVaultNote[]> =>
  Promise.all(files.map(async (file) => {
    const content = await readUtf8File(file.absolutePath);
    let frontmatter: Record<string, unknown> = {};

    try {
      frontmatter = parseYamlFrontmatter(content, file.relativePath).data;
    } catch {
      frontmatter = {};
    }

    return {
      absolutePath: file.absolutePath,
      relativePath: file.relativePath,
      canonicalTarget: getCanonicalTarget(file.relativePath),
      mtimeMs: file.mtimeMs,
      content,
      frontmatter,
      title: extractTitle(content, frontmatter, file.relativePath),
      noteType: parseOptionalString(frontmatter.note_type),
      status: parseOptionalString(frontmatter.status),
      updated: parseOptionalString(frontmatter.updated),
    } satisfies ParsedVaultNote;
  }));

const buildSignature = (files: readonly VaultFileRecord[]): string => {
  const hash = createHash('sha256');
  for (const file of files) {
    hash.update(`${file.relativePath}:${file.mtimeMs}\n`);
  }
  return hash.digest('hex');
};

const extractObsidianPaths = (value: unknown): string[] => {
  if (typeof value === 'string') {
    return [value];
  }

  if (Array.isArray(value)) {
    return value.flatMap((item) => extractObsidianPaths(item));
  }

  if (value && typeof value === 'object') {
    const record = value as Record<string, unknown>;
    const directPath = typeof record.path === 'string' ? [record.path] : [];
    const directFile = typeof record.file === 'string' ? [record.file] : [];
    const directName = typeof record.name === 'string' ? [record.name] : [];

    return [
      ...directPath,
      ...directFile,
      ...directName,
      ...Object.values(record).flatMap((item) => extractObsidianPaths(item)),
    ];
  }

  return [];
};

const readObsidianCliLinks = async (
  vaultRoot: string,
  relativePath: string,
  command: 'links' | 'backlinks',
): Promise<string[]> => {
  const { stdout } = await execFile('obsidian', [command, `path=${relativePath}`, 'format=json'], {
    cwd: vaultRoot,
    timeout: OBSIDIAN_TIMEOUT_MS,
  });

  const parsed = JSON.parse(stdout.trim() || '[]') as unknown;
  return [...new Set(extractObsidianPaths(parsed).map((entry) => normalizePathLikeValue(entry)).filter(Boolean))];
};

const buildFilesystemGraph = (vaultRoot: string, notes: readonly ParsedVaultNote[], signature: string): VaultGraph => {
  const canonicalTargets = new Set(notes.map((note) => note.canonicalTarget));
  const nodes = notes.map((note) => ({
    absolutePath: note.absolutePath,
    relativePath: note.relativePath,
    canonicalTarget: note.canonicalTarget,
    title: note.title,
    noteType: note.noteType,
    status: note.status,
    updated: note.updated,
    mtimeMs: note.mtimeMs,
    frontmatter: note.frontmatter,
    content: note.content,
    outgoingLinks: [...collectLinks(note.relativePath, note.content)].filter((target) => canonicalTargets.has(target)).sort(),
    incomingLinks: [] as string[],
  } satisfies VaultGraphNode));

  const nodesByCanonicalTarget = new Map(nodes.map((node) => [node.canonicalTarget, node]));
  for (const node of nodes) {
    for (const target of node.outgoingLinks) {
      const destination = nodesByCanonicalTarget.get(target);
      if (!destination) {
        continue;
      }
      destination.incomingLinks.push(node.canonicalTarget);
    }
  }

  for (const node of nodes) {
    node.incomingLinks.sort();
  }

  return {
    vaultRoot,
    resolver: 'filesystem',
    nodes,
    nodesByCanonicalTarget,
    signature,
  };
};

const buildObsidianGraph = async (vaultRoot: string, notes: readonly ParsedVaultNote[], signature: string): Promise<VaultGraph> => {
  const canonicalTargets = new Set(notes.map((note) => note.canonicalTarget));
  const nodes = notes.map((note) => ({
    absolutePath: note.absolutePath,
    relativePath: note.relativePath,
    canonicalTarget: note.canonicalTarget,
    title: note.title,
    noteType: note.noteType,
    status: note.status,
    updated: note.updated,
    mtimeMs: note.mtimeMs,
    frontmatter: note.frontmatter,
    content: note.content,
    outgoingLinks: [] as string[],
    incomingLinks: [] as string[],
  } satisfies VaultGraphNode));

  const nodesByCanonicalTarget = new Map(nodes.map((node) => [node.canonicalTarget, node]));

  await Promise.all(nodes.map(async (node) => {
    const [outgoing, incoming] = await Promise.all([
      readObsidianCliLinks(vaultRoot, node.relativePath, 'links'),
      readObsidianCliLinks(vaultRoot, node.relativePath, 'backlinks'),
    ]);

    node.outgoingLinks = outgoing.filter((target) => canonicalTargets.has(target) && target !== node.canonicalTarget).sort();
    node.incomingLinks = incoming.filter((target) => canonicalTargets.has(target) && target !== node.canonicalTarget).sort();
  }));

  for (const node of nodes) {
    if (node.incomingLinks.length > 0) {
      continue;
    }

    for (const source of nodes) {
      if (source.outgoingLinks.includes(node.canonicalTarget)) {
        node.incomingLinks.push(source.canonicalTarget);
      }
    }

    node.incomingLinks.sort();
  }

  return {
    vaultRoot,
    resolver: 'obsidian',
    nodes,
    nodesByCanonicalTarget,
    signature,
  };
};

export const invalidateVaultGraphCache = (vaultRoot?: string): void => {
  if (vaultRoot) {
    graphCache.delete(`${vaultRoot}:filesystem`);
    graphCache.delete(`${vaultRoot}:obsidian`);
    return;
  }
  graphCache.clear();
};

export const ensureVaultGraph = async (
  vaultRoot: string,
  resolver: VaultGraphResolver = 'filesystem',
): Promise<{ graph: VaultGraph; warnings: string[] }> => {
  const files = await scanVaultMarkdownFiles(vaultRoot);
  const signature = buildSignature(files);
  const cacheKey = `${vaultRoot}:${resolver}`;
  const cached = graphCache.get(cacheKey);
  if (cached && cached.signature === signature) {
    return { graph: cached.graph, warnings: [] };
  }

  const parsedNotes = await loadParsedVaultNotes(files);

  if (resolver === 'obsidian') {
    try {
      const graph = await buildObsidianGraph(vaultRoot, parsedNotes, signature);
      setGraphCache(cacheKey, { signature, graph });
      return { graph, warnings: [] };
    } catch (error) {
      const fallbackGraph = buildFilesystemGraph(vaultRoot, parsedNotes, signature);
      setGraphCache(`${vaultRoot}:filesystem`, { signature, graph: fallbackGraph });
      return {
        graph: fallbackGraph,
        warnings: [
          `Obsidian CLI resolver failed, falling back to filesystem links: ${error instanceof Error ? error.message : String(error)}`,
        ],
      };
    }
  }

  const graph = buildFilesystemGraph(vaultRoot, parsedNotes, signature);
  setGraphCache(cacheKey, { signature, graph });
  return { graph, warnings: [] };
};

const resolveTraversalRoot = (graph: VaultGraph, input: string): VaultGraphNode | undefined => {
  const normalizedInput = normalizePathLikeValue(input.trim().replace(/^\.\//, ''));
  if (normalizedInput.length === 0) {
    return undefined;
  }

  const exactMatch = graph.nodesByCanonicalTarget.get(normalizedInput);
  if (exactMatch) {
    return exactMatch;
  }

  const basenameMatches = graph.nodes.filter((node) => basename(node.canonicalTarget) === basename(normalizedInput));
  if (basenameMatches.length === 1) {
    return basenameMatches[0];
  }

  return undefined;
};

const normalizeFilterValues = (values: readonly string[] | undefined): Set<string> | null => {
  if (!values || values.length === 0) {
    return null;
  }

  const normalized = values
    .map((value) => value.trim().toLowerCase())
    .filter((value) => value.length > 0);

  return normalized.length > 0 ? new Set(normalized) : null;
};

const getTraversalNeighbors = (node: VaultGraphNode, direction: VaultTraverseDirection): string[] => {
  const neighborTargets = new Set<string>();
  if (direction === 'outgoing' || direction === 'both') {
    for (const target of node.outgoingLinks) {
      neighborTargets.add(target);
    }
  }
  if (direction === 'incoming' || direction === 'both') {
    for (const target of node.incomingLinks) {
      neighborTargets.add(target);
    }
  }
  return [...neighborTargets];
};

const nodeMatchesFilters = (
  node: VaultGraphNode,
  noteTypeFilter: Set<string> | null,
  statusFilter: Set<string> | null,
): boolean => {
  if (noteTypeFilter && !noteTypeFilter.has((node.noteType ?? '').toLowerCase())) {
    return false;
  }

  if (statusFilter && !statusFilter.has((node.status ?? '').toLowerCase())) {
    return false;
  }

  return true;
};

const excerptContent = (content: string, limit: number): { excerpt: string; truncated: boolean } => {
  if (content.length <= limit) {
    return { excerpt: content, truncated: false };
  }

  if (limit <= TRUNCATION_SUFFIX.length) {
    return {
      excerpt: TRUNCATION_SUFFIX.slice(0, limit),
      truncated: true,
    };
  }

  return {
    excerpt: `${content.slice(0, limit - TRUNCATION_SUFFIX.length)}${TRUNCATION_SUFFIX}`,
    truncated: true,
  };
};

const allocateContentExcerpts = (
  nodes: readonly VaultGraphNode[],
  rootTarget: string,
  discoveredDepths: ReadonlyMap<string, number>,
): { contentByTarget: Map<string, string>; truncated: boolean } => {
  const prioritizedNodes = [...nodes].sort((left, right) => {
    const leftRootRank = left.canonicalTarget === rootTarget ? 0 : 1;
    const rightRootRank = right.canonicalTarget === rootTarget ? 0 : 1;
    if (leftRootRank !== rightRootRank) {
      return leftRootRank - rightRootRank;
    }

    const leftDepth = discoveredDepths.get(left.canonicalTarget) ?? Number.POSITIVE_INFINITY;
    const rightDepth = discoveredDepths.get(right.canonicalTarget) ?? Number.POSITIVE_INFINITY;
    if (leftDepth !== rightDepth) {
      return leftDepth - rightDepth;
    }

    return left.relativePath.localeCompare(right.relativePath);
  });

  const contentByTarget = new Map<string, string>();
  let contentBudgetRemaining = TOTAL_CONTENT_LIMIT;
  let truncated = false;

  prioritizedNodes.forEach((node, index) => {
    if (contentBudgetRemaining <= 0) {
      truncated = true;
      return;
    }

    const remainingNodes = prioritizedNodes.length - index;
    const fairShare = Math.max(MIN_CONTENT_EXCERPT_LIMIT, Math.floor(contentBudgetRemaining / remainingNodes));
    const perNodeLimit = Math.min(
      node.canonicalTarget === rootTarget ? ROOT_CONTENT_EXCERPT_LIMIT : CONTENT_EXCERPT_LIMIT,
      fairShare,
      contentBudgetRemaining,
    );

    const excerpt = excerptContent(node.content, perNodeLimit);
    if (excerpt.truncated) {
      truncated = true;
    }

    contentByTarget.set(node.canonicalTarget, excerpt.excerpt);
    contentBudgetRemaining -= excerpt.excerpt.length;
  });

  return { contentByTarget, truncated };
};

export const traverseVaultGraph = (graph: VaultGraph, params: VaultTraverseParams, warnings: string[] = []): VaultTraverseResult => {
  const rootNode = resolveTraversalRoot(graph, params.root);
  if (!rootNode) {
    throw new Error(`Could not resolve traversal root: ${params.root}`);
  }

  const maxNotes = Math.max(1, params.maxNotes ?? 500);
  const noteTypeFilter = normalizeFilterValues(params.noteTypes);
  const statusFilter = normalizeFilterValues(params.statuses);
  const filtersActive = noteTypeFilter !== null || statusFilter !== null;
  const visited = new Set<string>([rootNode.canonicalTarget]);
  const included = new Set<string>([rootNode.canonicalTarget]);
  const discoveredDepths = new Map<string, number>([[rootNode.canonicalTarget, 0]]);
  const queue: Array<{ target: string; depth: number }> = [{ target: rootNode.canonicalTarget, depth: 0 }];
  const matchMemo = new Map<string, boolean>();
  let truncated = false;

  const canReachIncludedNode = (target: string, remainingDepth: number, activeKeys = new Set<string>()): boolean => {
    const memoKey = `${target}:${remainingDepth}`;
    const memoized = matchMemo.get(memoKey);
    if (memoized !== undefined) {
      return memoized;
    }

    const node = graph.nodesByCanonicalTarget.get(target);
    if (!node) {
      matchMemo.set(memoKey, false);
      return false;
    }

    if (nodeMatchesFilters(node, noteTypeFilter, statusFilter)) {
      matchMemo.set(memoKey, true);
      return true;
    }

    if (remainingDepth <= 0) {
      matchMemo.set(memoKey, false);
      return false;
    }

    activeKeys.add(memoKey);
    for (const neighbor of getTraversalNeighbors(node, params.direction)) {
      const childKey = `${neighbor}:${remainingDepth - 1}`;
      if (activeKeys.has(childKey)) {
        continue;
      }

      if (canReachIncludedNode(neighbor, remainingDepth - 1, activeKeys)) {
        activeKeys.delete(memoKey);
        matchMemo.set(memoKey, true);
        return true;
      }
    }

    activeKeys.delete(memoKey);
    matchMemo.set(memoKey, false);
    return false;
  };

  while (queue.length > 0) {
    const current = queue.shift();
    if (!current) {
      break;
    }

    if (current.depth >= params.depth) {
      continue;
    }

    const node = graph.nodesByCanonicalTarget.get(current.target);
    if (!node) {
      continue;
    }

    for (const target of getTraversalNeighbors(node, params.direction)) {
      if (visited.has(target)) {
        continue;
      }

      const nextDepth = current.depth + 1;
      const remainingDepth = params.depth - nextDepth;
      const candidate = graph.nodesByCanonicalTarget.get(target);
      if (!candidate) {
        visited.add(target);
        continue;
      }

      if (filtersActive && !canReachIncludedNode(target, remainingDepth)) {
        visited.add(target);
        continue;
      }

      if (included.size >= maxNotes) {
        truncated = true;
        continue;
      }

      visited.add(target);
      queue.push({ target, depth: nextDepth });

      if (!nodeMatchesFilters(candidate, noteTypeFilter, statusFilter)) {
        continue;
      }

      included.add(target);
      discoveredDepths.set(target, nextDepth);
    }
  }

  const filteredNodes = [...included]
    .map((target) => graph.nodesByCanonicalTarget.get(target))
    .filter((node): node is VaultGraphNode => Boolean(node))
    .sort((left, right) => left.relativePath.localeCompare(right.relativePath));

  const includedTargets = new Set(filteredNodes.map((node) => node.canonicalTarget));
  const contentByTarget = new Map<string, string>();
  if (params.includeContent) {
    const allocatedContent = allocateContentExcerpts(filteredNodes, rootNode.canonicalTarget, discoveredDepths);
    truncated ||= allocatedContent.truncated;
    for (const [target, content] of allocatedContent.contentByTarget.entries()) {
      contentByTarget.set(target, content);
    }
  }

  const notes = filteredNodes.map((node) => ({
    path: node.relativePath,
    title: node.title,
    noteType: node.noteType,
    status: node.status,
    updated: node.updated,
    ...(contentByTarget.has(node.canonicalTarget) ? { content: contentByTarget.get(node.canonicalTarget) } : {}),
  } satisfies VaultTraverseResultNode));

  const edges = filteredNodes.flatMap((node) => {
    const neighborTargets = getTraversalNeighbors(node, params.direction);

    return neighborTargets
      .filter((target) => includedTargets.has(target))
      .map((target) => ({ from: node.relativePath, to: graph.nodesByCanonicalTarget.get(target)?.relativePath ?? target }))
      .filter((edge) => typeof edge.to === 'string')
      .sort((left, right) => left.to.localeCompare(right.to));
  });

  return {
    meta: {
      root: rootNode.relativePath,
      depth: params.depth,
      direction: params.direction,
      resolverRequested: params.resolver ?? 'filesystem',
      resolverUsed: graph.resolver,
      totalNotes: notes.length,
      truncated,
      warnings,
      ...(noteTypeFilter ? { noteTypes: [...noteTypeFilter] } : {}),
      ...(statusFilter ? { statuses: [...statusFilter] } : {}),
    },
    notes,
    edges,
  };
};

export const formatVaultTraverseResultAsJson = (result: VaultTraverseResult): string =>
  JSON.stringify(result, null, 2);

export const formatVaultTraverseResultAsToon = (result: VaultTraverseResult): string =>
  encode(result, { delimiter: '\t', keyFolding: 'safe' });

import { existsSync } from 'fs';
import { readFile } from 'fs/promises';
import { resolveVaultRelativePath } from './vault-files';
import { readGeneratedBlockContent, readGeneratedBlockWithMarkers, readHeadingSectionContent } from './note-mutations';

export interface VaultNoteExtractionParams {
  readonly notePath: string;
  readonly heading?: string;
  readonly block?: string;
  readonly includeMarkers?: boolean;
}

export interface VaultNoteExtractionResult {
  readonly notePath: string;
  readonly selector: string;
  readonly content: string;
}

const normalizeNotePath = (notePath: string): string => {
  const normalized = notePath.replace(/\\/g, '/').replace(/^\/+/, '');
  return normalized.toLowerCase().endsWith('.md') ? normalized : `${normalized}.md`;
};

const ensureExtractableNoteContent = (content: string): string =>
  content.startsWith('---\n') || content.startsWith('---\r\n')
    ? content
    : `---\nsynthetic: true\n---\n\n${content}`;

const countSelectors = (params: VaultNoteExtractionParams): number =>
  [params.heading, params.block].filter((value) => typeof value === 'string' && value.trim().length > 0).length;

export const extractVaultNoteTarget = async (
  vaultRoot: string,
  params: VaultNoteExtractionParams,
): Promise<VaultNoteExtractionResult> => {
  const notePath = normalizeNotePath(params.notePath);
  const selectorCount = countSelectors(params);
  if (selectorCount !== 1) {
    throw new Error('Targeted extraction requires exactly one selector: heading or block.');
  }

  const absolutePath = resolveVaultRelativePath(vaultRoot, notePath);
  if (!existsSync(absolutePath)) {
    throw new Error(`Note does not exist: ${notePath}`);
  }

  const content = await readFile(absolutePath, 'utf-8');
  const extractableContent = ensureExtractableNoteContent(content);
  const noteContext = notePath;

  if (params.heading && params.heading.trim().length > 0) {
    const heading = params.heading.trim();
    return {
      notePath,
      selector: `heading:${heading}`,
      content: readHeadingSectionContent(extractableContent, heading, noteContext),
    };
  }

  const block = params.block?.trim();
  if (!block) {
    throw new Error('Targeted extraction requires exactly one selector: heading or block.');
  }

  return {
    notePath,
    selector: `block:${block}`,
    content: params.includeMarkers === false
      ? readGeneratedBlockContent(extractableContent, block, noteContext)
      : readGeneratedBlockWithMarkers(extractableContent, block, noteContext),
  };
};

import { readFile } from 'fs/promises';
import { join } from 'path';
import { encode } from '@toon-format/toon';
import type { AgentVaultCommandEnvironment } from './note-generators';
import { formatCommandHelp } from './command-catalog';
import { resolveVaultRoot } from './vault-files';
import type { CodeGraphIndexPayload, CodeGraphIndexV3, CodeSymbolV3 } from '../scaffold/code-graph';

export interface CodeGraphLookupMatch {
  readonly file: string;
  readonly language: string;
  readonly symbol: CodeSymbolV3;
}

export interface QueryCodeGraphIndexInput {
  readonly query: string;
  readonly limit: number;
  readonly pathSubstring?: string;
  readonly exportedOnly?: boolean;
}

export interface FormatCodeGraphLookupToonOptions {
  readonly compact?: boolean;
}

const CODE_GRAPH_INDEX_PATH = join('08_Automation', 'code-graph', 'index.json');

const normalize = (value: string): string => value.trim().toLowerCase();

const parsePositiveIntOption = (flag: string, value: string | undefined): number => {
  if (!value) {
    throw new Error(`Missing value for ${flag}`);
  }
  const parsed = Number.parseInt(value, 10);
  if (!Number.isFinite(parsed) || parsed <= 0) {
    throw new Error(`${flag} must be a positive integer`);
  }
  return parsed;
};

export type CodeGraphIndex = CodeGraphIndexPayload | CodeGraphIndexV3;

export async function loadCodeGraphIndex(vaultRoot: string): Promise<CodeGraphIndex> {
  const raw = await readFile(join(vaultRoot, CODE_GRAPH_INDEX_PATH), 'utf-8');
  const parsed = JSON.parse(raw) as { version: number };
  // Both v2 and v3 are compatible for lookup purposes; return as-is
  return parsed as CodeGraphIndex;
}

export function queryCodeGraphIndex(
  index: CodeGraphIndex,
  { query, limit, pathSubstring, exportedOnly }: QueryCodeGraphIndexInput,
): CodeGraphLookupMatch[] {
  const normalizedQuery = normalize(query);
  const normalizedPath = pathSubstring ? normalize(pathSubstring) : undefined;
  const matches: CodeGraphLookupMatch[] = [];

  for (const file of index.files) {
    if (normalizedPath && !file.path.toLowerCase().includes(normalizedPath)) {
      continue;
    }

    for (const symbol of file.symbols) {
      if (exportedOnly && !symbol.exported) {
        continue;
      }
      if (!symbol.name.toLowerCase().includes(normalizedQuery)) {
        continue;
      }

      matches.push({ file: file.path, language: file.language, symbol });
      if (matches.length >= limit) {
        return matches;
      }
    }
  }

  return matches;
}

const parseLookupArgs = (argv: string[]): {
  query?: string;
  limit: number;
  pathSubstring?: string;
  exportedOnly: boolean;
  helpRequested: boolean;
} => {
  const positionals: string[] = [];
  let limit = 10;
  let pathSubstring: string | undefined;
  let exportedOnly = false;
  let helpRequested = false;

  for (let i = 0; i < argv.length; i++) {
    const token = argv[i];
    if (token === '--help' || token === '-h') {
      helpRequested = true;
      continue;
    }
    if (token === '--exports-only') {
      exportedOnly = true;
      continue;
    }
    if (token === '--limit') {
      limit = parsePositiveIntOption('--limit', argv[++i]);
      continue;
    }
    if (token === '--path') {
      const next = argv[++i];
      if (!next) throw new Error('Missing value for --path');
      pathSubstring = next;
      continue;
    }
    if (token.startsWith('--')) {
      throw new Error(`Unknown option: ${token}`);
    }
    positionals.push(token);
  }

  return {
    query: positionals[0],
    limit,
    pathSubstring,
    exportedOnly,
    helpRequested,
  };
};

export function formatCodeGraphLookupResults(matches: CodeGraphLookupMatch[], query: string): string {
  const header = `Code graph lookup: ${matches.length} match${matches.length === 1 ? '' : 'es'} for "${query}"`;
  if (matches.length === 0) {
    return `${header}\n\nNo matches found.`;
  }

  return [
    header,
    '',
    ...matches.map((match) => {
      const exportedLabel = match.symbol.exported ? 'exported' : 'internal';
      return `- ${match.file}:${match.symbol.line} — ${match.symbol.kind} ${match.symbol.name} (${match.language}, ${exportedLabel})`;
    }),
  ].join('\n');
}

export function formatCodeGraphLookupResultsAsToon(
  index: CodeGraphIndex,
  matches: CodeGraphLookupMatch[],
  query: string,
  options: FormatCodeGraphLookupToonOptions = {},
): string {
  const compact = options.compact ?? false;

  if (compact) {
    const groupedMatches = Object.entries(matches.reduce<Record<string, { language: string; symbols: Array<{ name: string; kind: string; line: number; exported: boolean }> }>>((acc, match) => {
      const existing = acc[match.file] ?? { language: match.language, symbols: [] };
      existing.symbols.push({
        name: match.symbol.name,
        kind: match.symbol.kind,
        line: match.symbol.line,
        exported: match.symbol.exported,
      });
      acc[match.file] = existing;
      return acc;
    }, {})).map(([file, value]) => ({ file, ...value }));

    return encode({
      q: query,
      c: matches.length,
      f: groupedMatches,
    }, { delimiter: '\t', keyFolding: 'safe' });
  }

  // v2 has repoName, v3 has root; use whichever is available
  const index2 = index as CodeGraphIndexPayload;
  const index3 = index as CodeGraphIndexV3;
  return encode({
    repoName: index2.repoName,
    root: index3.root,
    generatedAt: index2.generatedAt,
    query,
    matchCount: matches.length,
    matches,
  }, { delimiter: '\t', keyFolding: 'safe' });
}

export async function handleLookupCodeGraphCommand(
  argv: string[],
  environment: AgentVaultCommandEnvironment = {},
): Promise<number> {
  const io = environment.io ?? {
    stdout: (message: string) => console.log(message),
    stderr: (message: string) => console.error(message),
  };

  try {
    const parsed = parseLookupArgs(argv);
    if (parsed.helpRequested) {
      io.stdout(formatCommandHelp('lookup-code-graph'));
      return 0;
    }
    if (!parsed.query) {
      io.stderr('lookup-code-graph requires a query.');
      io.stdout('');
      io.stdout(formatCommandHelp('lookup-code-graph'));
      return 1;
    }

    const vaultRoot = environment.vaultRoot ?? resolveVaultRoot(environment.cwd ? environment.cwd() : process.cwd());
    const index = await loadCodeGraphIndex(vaultRoot);
    const matches = queryCodeGraphIndex(index, {
      query: parsed.query,
      limit: parsed.limit,
      pathSubstring: parsed.pathSubstring,
      exportedOnly: parsed.exportedOnly,
    });
    io.stdout(formatCodeGraphLookupResults(matches, parsed.query));
    return 0;
  } catch (error) {
    io.stderr(error instanceof Error ? error.message : String(error));
    return 1;
  }
}

import { encode } from '@toon-format/toon';
import type { VaultConfig } from './vault-config';
import type { InitResult } from '../scaffold/init';
import type { ScanResult } from '../scaffold/scan';

const pruneForToon = (value: unknown): unknown => {
  if (Array.isArray(value)) {
    const next = value
      .map((item) => pruneForToon(item))
      .filter((item) => item !== undefined);
    return next.length > 0 ? next : undefined;
  }

  if (value && typeof value === 'object') {
    const entries = Object.entries(value)
      .map(([key, item]) => [key, pruneForToon(item)] as const)
      .filter(([, item]) => item !== undefined);
    return entries.length > 0 ? Object.fromEntries(entries) : undefined;
  }

  if (value === null || value === undefined || value === '') {
    return undefined;
  }

  return value;
};

const encodePruned = (value: unknown): string =>
