const EXTRACTORS: Record<string, SymbolExtractorV3> = {
  TypeScript: extractTypeScript,
  JavaScript: extractTypeScript,
  Python: extractPython,
  Go: extractGo,
  Rust: extractRust,
  Java: extractJava,
  Kotlin: extractKotlin,
  Ruby: extractRuby,
  'C#': extractCSharp,
  Swift: extractSwift,
  PHP: extractPHP,
  Scala: extractScala,
  Elixir: extractElixir,
};

import { createTieredAnalyzer, type TieredSourceAnalyzer } from './source-analyzer';

const GENERATED_DIRS = new Set(['.next', '.nuxt', '.svelte-kit', 'dist', 'build', 'out', '__pycache__', '.gradle']);
const VENDOR_DIRS = new Set(['node_modules', '.git', '.agent-vault', 'vendor', '.venv', 'venv', '.idea', '.vscode', 'coverage', '.planning', '.obsidian']);

async function walkSourceFiles(
  projectRoot: string,
  dir: string,
  results: FileSymbolsV3[],
  tieredAnalyzer?: TieredSourceAnalyzer,
  depth = 0,
): Promise<void> {
  if (depth > 8) return;

  const entries = await readdir(dir, { withFileTypes: true });

  for (const entry of entries) {
    const fullPath = join(dir, entry.name);

    if (entry.isDirectory()) {
      if (!SKIP_DIRS.has(entry.name)) {
        await walkSourceFiles(projectRoot, fullPath, results, tieredAnalyzer, depth + 1);
      }
      continue;
    }

    if (!entry.isFile()) continue;

    const ext = extname(entry.name);
    const language = LANGUAGE_EXTENSIONS[ext];
    if (!language) continue;

    if (entry.name.includes('.test.') || entry.name.includes('.spec.')) continue;

    try {
      const content = await readFile(fullPath, 'utf-8');
      if (content.length > 500_000) continue;

      const extractor = EXTRACTORS[language];
      if (!extractor) continue;

      let symbols: CodeSymbolV3[] = [];
      let imports: ImportEdge[] | undefined;
      let exports: ExportEdge[] | undefined;
      let parserTier: AnalysisTier = 'regex';

      // Try the tiered analyzer for TS/JS when available
      if (tieredAnalyzer && (language === 'TypeScript' || language === 'JavaScript')) {
        try {
          const analysisResult = await tieredAnalyzer.analyze(fullPath, content, language);
          if (analysisResult && analysisResult.symbols.length > 0) {
            symbols = analysisResult.symbols as CodeSymbolV3[];
            imports = analysisResult.imports as ImportEdge[];
            exports = analysisResult.exports as ExportEdge[];
            parserTier = analysisResult.tier;
          } else {
            // Tiered analyzer returned empty, fall back to regex
            symbols = extractor(content);
            imports = extractImportEdges(content);
            exports = extractExportEdges(content);
            parserTier = 'regex';
          }
        } catch {
          // Tiered analyzer threw, fall back to regex
          symbols = extractor(content);
          imports = extractImportEdges(content);
          exports = extractExportEdges(content);
          parserTier = 'regex';
        }
      } else {
        // Use regex extractor for non-TS/JS languages or when no tiered analyzer
        symbols = extractor(content);
        if (language === 'TypeScript' || language === 'JavaScript') {
          imports = extractImportEdges(content);
          exports = extractExportEdges(content);
        }
      }

      if (symbols.length > 0) {
        const relativePath = relative(projectRoot, fullPath).replace(/\\/g, '/');
        const fileStats = await stat(fullPath);
        const hash = createHash('sha256').update(content).digest('hex');

        // Determine flags
        const rel = relative(projectRoot, dir).replace(/\\/g, '/');
        const genArray = [...GENERATED_DIRS];
        const vendArray = [...VENDOR_DIRS];
        const generated = GENERATED_DIRS.has(rel) || genArray.some((d: string) => relativePath.includes('/' + d + '/'));
        const vendor = VENDOR_DIRS.has(rel) || vendArray.some((d: string) => relativePath.includes('/' + d + '/'));

        const fileResult: FileSymbolsV3 = {
          path: relativePath,
          language,
          symbols,
          imports,
          exports,
          hash,
          mtimeMs: fileStats.mtimeMs,
          size: fileStats.size,
          generated,
          vendor,
          parser: parserTier,
        };

        results.push(fileResult);
      }
    } catch {
      // Skip unreadable files
    }
  }
}

export async function buildCodeGraph(projectRoot: string): Promise<CodeGraphResult> {
  const files: FileSymbolsV3[] = [];

  // Create tiered analyzer for TS/JS files
  const tieredAnalyzer = createTieredAnalyzer({
    typescript: extractTypeScript,
    other: {
      Python: extractPython,
      Go: extractGo,
      Rust: extractRust,
      Java: extractJava,
      Kotlin: extractKotlin,
      Ruby: extractRuby,
      'C#': extractCSharp,
      Swift: extractSwift,
      PHP: extractPHP,
      Scala: extractScala,
      Elixir: extractElixir,
    },
    imports: extractImportEdges,
    exports: extractExportEdges,
  });

  await walkSourceFiles(projectRoot, projectRoot, files, tieredAnalyzer);

  files.sort((a, b) => a.path.localeCompare(b.path));
  const totalSymbols = files.reduce((sum, f) => sum + f.symbols.length, 0);

  return { files, totalFiles: files.length, totalSymbols };
}

export function summarizeCodeGraph(graph: CodeGraphResult): CodeGraphDirectorySummary[] {
  const byDirectory = new Map<string, CodeGraphDirectorySummary>();

  for (const file of graph.files) {
    const directory = file.path.includes('/') ? file.path.slice(0, file.path.lastIndexOf('/')) : '.';
    const exportedSymbols = file.symbols.filter((symbol) => symbol.exported).length;
    const internalSymbols = file.symbols.length - exportedSymbols;
    const existing = byDirectory.get(directory) ?? {
      directory,
      files: 0,
      exportedSymbols: 0,
      internalSymbols: 0,
      totalSymbols: 0,
    };

    byDirectory.set(directory, {
      directory,
      files: existing.files + 1,
      exportedSymbols: existing.exportedSymbols + exportedSymbols,
      internalSymbols: existing.internalSymbols + internalSymbols,
      totalSymbols: existing.totalSymbols + file.symbols.length,
    });
  }

  return Array.from(byDirectory.values()).sort((left, right) => {
    if (right.totalSymbols !== left.totalSymbols) return right.totalSymbols - left.totalSymbols;
    return left.directory.localeCompare(right.directory);
  });
}

export function buildCodeGraphIndexPayloadV3(graph: CodeGraphResult, root: string, generatedAt = new Date().toISOString()): CodeGraphIndexV3 {
  return {
    version: 3,
    generatedAt,
    root,
    files: graph.files,
  };
}

// Keep v2 for backward compatibility (used by older lookups)
export function buildCodeGraphIndexPayload(graph: CodeGraphResult, repoName: string, generatedAt = new Date().toISOString()): CodeGraphIndexPayload {
  return {
    version: 2,
    generatedAt,
    repoName,
    totalFiles: graph.totalFiles,
    totalSymbols: graph.totalSymbols,
    directories: summarizeCodeGraph(graph),
    files: graph.files.map(f => ({ path: f.path, language: f.language, symbols: f.symbols })),
  };
}

export function renderCodeGraphMarkdown(graph: CodeGraphResult, repoName: string): string {
  const date = new Date().toISOString().slice(0, 10);
  const directories = summarizeCodeGraph(graph).slice(0, 8);

  const sections: string[] = [
    `---`,
    `note_type: architecture`,
    `template_version: 2`,
    `contract_version: 1`,
    `title: Code Graph`,
    `architecture_id: "ARCH-0006"`,
    `status: active`,
    `owner: ""`,
    `reviewed_on: "${date}"`,
    `created: "${date}"`,
    `updated: "${date}"`,
    `related_notes:`,
    `  - "[[01_Architecture/Code_Map|Code Map]]"`,
    `  - "[[01_Architecture/System_Overview|System Overview]]"`,
    `tags:`,
    `  - agent-vault`,
    `  - architecture`,
    `---`,
    ``,
    `# Code Graph`,
    ``,
    `## Purpose`,
    ``,
    `- Provide a low-cost navigation summary for the indexed codebase.`,
    `- Keep default vault context small while preserving machine-readable symbol lookup.`,
    `- Point agents and engineers to the generated JSON index when detailed symbol data is needed.`,
    ``,
    `## Overview`,
    ``,
    `- Repository: ${repoName}`,
    `- Files indexed: ${graph.totalFiles}`,
    `- Symbols found: ${graph.totalSymbols}`,
    `- Detailed index path: \`.agent-vault/08_Automation/code-graph/index.json\``,
    ``,
    `## Key Components`,
    ``,
    `- The markdown note is intentionally thin and should stay safe to include in routine vault traversals.`,
    `- The JSON index is the source for detailed symbol-to-file lookup.`,
    `- Directory summaries below show where most indexed code lives without inlining the full symbol table.`,
    ``,
    `## Important Paths`,
    ``,
    `- \`.agent-vault/01_Architecture/Code_Graph.md\` — compact human summary.`,
    `- \`.agent-vault/08_Automation/code-graph/index.json\` — full machine-readable index.`,
    ``,
    `## Constraints`,
    ``,
    `- Auto-generated during vault initialization and \`vault_refresh target=code_graph\`; do not hand-edit.`,
    `- This note must remain concise; full symbol dumps belong only in the JSON index.`,
    `- Files larger than 500 KB and common generated/test files are excluded.`,
    ``,
    `## Failure Modes`,
    ``,
    `- If source files are added outside the supported language set, they will not appear in the index.`,
    `- If the JSON index is stale, refresh the code graph before using it for lookup-heavy tasks.`,
    `- Deeply nested files (beyond 8 levels) are skipped.`,
    ``,
    `## How to Use`,
    ``,
    `1. Read this note first for a cheap overview.`,
    `2. For low-cost symbol/file discovery, use \`vault_lookup_code_graph\` instead of loading the full JSON index into prompt context.`,
    `3. Read the JSON index directly only for tooling or explicit offline inspection.`,
    `4. Use lookup results to narrow to a small set of source files before reading code.`,
    ``,
    `## Directory Hotspots`,
    ``,

  ];

  if (directories.length === 0) {
    sections.push(`- No indexed source files were found.`, ``);
  } else {
    for (const directory of directories) {
      sections.push(`- \`${directory.directory}\`: ${directory.files} files, ${directory.exportedSymbols} exported symbols, ${directory.internalSymbols} internal symbols`);
    }
    sections.push('');
  }

  sections.push(
    `## Related Notes`,
    ``,
    `<!-- AGENT-START:architecture-related-notes -->`,
    `- [[01_Architecture/Code_Map|Code Map]]`,
    `- [[01_Architecture/System_Overview|System Overview]]`,
    `<!-- AGENT-END:architecture-related-notes -->`,
    ``,
  );

  return sections.join('\n');
}

export async function writeCodeGraph(
  projectRoot: string,
  vaultRoot: string,
  repoName: string,
): Promise<CodeGraphResult> {
  const graph = await buildCodeGraph(projectRoot);
  const markdown = renderCodeGraphMarkdown(graph, repoName);
  const indexPayload = buildCodeGraphIndexPayloadV3(graph, projectRoot);

  const outputPath = join(vaultRoot, '01_Architecture', 'Code_Graph.md');
  const indexDir = join(vaultRoot, '08_Automation', 'code-graph');
  const indexPath = join(indexDir, 'index.json');

  await mkdir(join(vaultRoot, '01_Architecture'), { recursive: true });
  await mkdir(indexDir, { recursive: true });
  await writeFile(outputPath, markdown, 'utf-8');
  await writeFile(indexPath, JSON.stringify(indexPayload, null, 2) + '\n', 'utf-8');
  return graph;
}

export function findSymbols(
  graph: CodeGraphResult,
  query: string,
): Array<{ file: string; symbol: CodeSymbolV3 }> {
  const results: Array<{ file: string; symbol: CodeSymbolV3 }> = [];
  const lowerQuery = query.toLowerCase();

  for (const file of graph.files) {
    for (const symbol of file.symbols) {
      if (symbol.name.toLowerCase().includes(lowerQuery)) {
        results.push({ file: file.path, symbol });
      }
    }
  }

  return results;
}

export function getSymbolsForFiles(
  graph: CodeGraphResult,
  filePaths: string[],
): Map<string, CodeSymbolV3[]> {
  const result = new Map<string, CodeSymbolV3[]>();

  for (const queryPath of filePaths) {
    for (const file of graph.files) {
      if (file.path === queryPath || file.path.endsWith(queryPath) || file.path.includes(queryPath)) {
        const existing = result.get(file.path) ?? [];
        existing.push(...file.symbols.filter((s) => s.exported));
        result.set(file.path, existing);
      }
    }
  }

  return result;
}

import { createHash } from 'crypto';
import { existsSync } from 'fs';
import { mkdir, readFile, stat, writeFile } from 'fs/promises';
import { basename, extname, join, relative, resolve } from 'path';

// ─── Types ────────────────────────────────────────────────────────────

export interface StubManifestEntry {
  /** Project-relative source path (e.g. "src/core/vault-graph.ts") */
  readonly path: string;
  /** Language detected from file extension */
  readonly language: string;
  /** Source file size in bytes */
  readonly size: number;
  /** Source file mtime in milliseconds since epoch */
  readonly mtimeMs: number;
  /** SHA-256 hex digest of source file content */
  readonly sha256: string;
  /** Stub schema version */
  readonly stubVersion: 1;
  /** Parser used: 'regex' for initial regex-based, later 'typescript-compiler' or 'tree-sitter' */
  readonly parser: string;
  /** Path within the vault automation directory to the generated stub file */
  readonly stubPath: string;
  /** Set to true when the stub is incomplete (fallback, partial extraction, etc.) */
  readonly incomplete?: boolean;
}

export interface StubManifest {
  /** Manifest schema version */
  readonly version: 1;
  /** ISO-8601 timestamp when manifest was generated */
  generatedAt: string;
  /** Ordered list of stub entries */
  entries: StubManifestEntry[];
}

export interface GenerateStubResult {
  /** Whether a new stub was generated (true) or served from cache (false) */
  readonly generated: boolean;
  /** Path to the generated stub file (relative to vault root) */
  readonly stubPath: string;
  /** Whether the stub is complete or a fallback/incomplete version */
  readonly incomplete: boolean;
}

export interface GenerateStubsResult {
  /** Number of new stubs generated */
  readonly generated: number;
  /** Total number of stubs in manifest */
  readonly total: number;
  /** Any warnings encountered */
  readonly warnings: string[];
}

// ─── Constants ────────────────────────────────────────────────────────

const STUBS_DIR = 'code-stubs';
const STUB_EXT = '.stub.ts';
const MAX_FILE_SIZE = 500_000; // 500KB limit, same as code-graph

// ─── Path sanitization ────────────────────────────────────────────────

/**
 * Convert a project-relative path like "src/core/vault-graph.ts" into a safe
 * stub filename like "src_core_vault-graph.ts.a1b2c3d4.stub.ts".
 *
 * The hash prefix prevents collisions when multiple source paths map to the same
 * sanitized base name.
 */
export function sanitizeStubPath(projectRelativePath: string, sha256: string): string {
  const base = basename(projectRelativePath, extname(projectRelativePath));
  const sanitized = projectRelativePath
    .replace(/\.[^.]+$/, '') // remove extension
    .replace(/[^a-zA-Z0-9_\-\.]/g, '_') // sanitize separators
    .replace(/_{2,}/g, '_'); // collapse multiple underscores

  const hashPrefix = sha256.slice(0, 8);
  return `${sanitized}.${hashPrefix}${STUB_EXT}`;
}

/**
 * Resolve the vault-relative stub file path for a given source file.
 * Returns undefined if the stub doesn't exist on disk.
 */
export function resolveStubPath(vaultRoot: string, manifestEntry: StubManifestEntry): string | undefined {
  const absoluteStub = resolve(vaultRoot, STUBS_DIR, manifestEntry.stubPath);
  return existsSync(absoluteStub) ? manifestEntry.stubPath : undefined;
}

// ─── Stub content generation ────────────────────────────────────────

/**
 * Generate a TypeScript stub from source content.
 *
 * Rules per DEC-0003:
 * - Do not invent behavior
 * - Keep exported declarations, public signatures, interfaces, types, enums, constants
 * - Keep useful docstrings where safely extractable
 * - Keep import/export relationships
 * - Drop function/method bodies
 * - Preserve line references when possible
 * - Mark incomplete/fallback stubs clearly
 *
 * This is the initial regex-based parser; STEP-04-06 will add TypeScript compiler
 * and Tree-sitter backends for higher fidelity.
 */
export function generateTypeScriptStub(content: string): { stubContent: string; incomplete: boolean } {
  const lines = content.split('\n');
  const outputLines: string[] = [];
  let incomplete = false;
  let inFunctionBody = false;
  let braceDepth = 0;
  let inClass = false;
  let classDepth = 0;
  let currentMethodName = '';

  // We process line-by-line, tracking brace depth to identify function/class bodies.
  // Strategy:
  // 1. Keep all import statements
  // 2. For function declarations (export function / async function / arrow), emit a declaration stub
  // 3. For classes, emit a declare class with declare methods
  // 4. For interfaces, types, enums, constants: keep as-is
  // 5. Drop all implementation bodies

  let i = 0;
  while (i < lines.length) {
    const line = lines[i];
    const trimmed = line.trim();

    // ── Keep JSDoc / block comments ──
    if (trimmed.startsWith('/**') || trimmed.startsWith('*') || trimmed.startsWith('/*') || trimmed.startsWith('*/')) {
      outputLines.push(line);
      i++;
      continue;
    }

    // ── Keep single-line comments ──
    if (trimmed.startsWith('//')) {
      outputLines.push(line);
      i++;
      continue;
    }

    // ── Keep import statements ──
    if (/^import\s+/.test(trimmed)) {
      outputLines.push(line);
      i++;
      continue;
    }

    // ── Handle function declarations ──
    const fnMatch = /^(export\s+(?:async\s+)?)?(?:function\s+)(\w+)\s*\(([^)]*)\)(\s*:\s*(\S+))?\s*(?:=|{|$)/.exec(trimmed);
    if (fnMatch && !line.startsWith('import')) {
      const isExport = !!fnMatch[1];
      const name = fnMatch[2];
      const params = fnMatch[3];
      const returnType = fnMatch[5] || '';
      const hasBody = trimmed.includes('{');

      if (hasBody) {
        // Convert to declare form: export declare function name(params): ReturnType;
        const declarePrefix = isExport ? 'export declare' : 'declare';
        const ret = returnType ? `: ${returnType}` : '';
        outputLines.push(`${declarePrefix} function ${name}(${params})${ret};`);

        // Skip the function body
        if (trimmed.endsWith('{') || (i + 1 < lines.length && lines[i + 1].trim() === '{')) {
          braceDepth = 1;
          let j = i + 1;
          while (j < lines.length && braceDepth > 0) {
            const l = lines[j].trim();
            braceDepth += (l.match(/\{/g) || []).length;
            braceDepth -= (l.match(/\}/g) || []).length;
            j++;
          }
          i = j;
          incomplete = true; // We're approximating via regex
        } else {
          i++;
        }
      } else {
        // Arrow function or function expression assignment — skip
        if (/=\s*\(/.test(trimmed) || /=>/.test(trimmed)) {
          // Arrow function assignment — try to get the signature
          const arrowMatch = /^(export\s+(?:const|let|var)\s+)?(\w+)\s*=\s*(?:async\s+)?\(([^)]*)\)(\s*:\s*(\S+))?\s*=>/.exec(trimmed);
          if (arrowMatch) {
            const isExport = !!arrowMatch[1];
            const ret = arrowMatch[5] || '';
            const declarePrefix = isExport ? 'export declare' : 'declare';
            outputLines.push(`${declarePrefix} const ${arrowMatch[2]}: (${arrowMatch[3]})${ret ? `: ${ret}` : ''}`);
          }
        }
        i++;
      }
      continue;
    }

    // ── Handle class declarations ──
    const classMatch = /^(export\s+)?(?:abstract\s+)?class\s+(\w+)/.exec(trimmed);
    if (classMatch && !line.startsWith('import')) {
      const isExport = !!classMatch[1];
      const className = classMatch[2];

      // Emit a declare class with empty body
      const declarePrefix = isExport ? 'export declare' : 'declare';
      const isAbstract = trimmed.startsWith('abstract');
      outputLines.push(`${declarePrefix} ${isAbstract ? 'abstract ' : ''}class ${className} { }`);
      outputLines.push('');

      incomplete = true;
      i++;
      continue;
    }

    // ── Keep interfaces, types, enums, and constants ──
    if (/^export\s+(interface|type|enum|const|let|var)\s+\w+/.test(trimmed)) {
      // Check if this is a const/let/var with an initializer that is a function expression
      const constFnMatch = /^(export\s+)?(?:const|let|var)\s+(\w+)\s*=\s*(?:async\s+)?\(/.exec(trimmed);
      if (constFnMatch) {
        // This is a function assigned to a const — emit declare form
        const isExport = !!constFnMatch[1];
        const name = constFnMatch[2];
        const declarePrefix = isExport ? 'export declare' : 'declare';
        outputLines.push(`${declarePrefix} const ${name}: Function;`);
        incomplete = true;
        i++;
        continue;
      }

      // Keep the full declaration (interfaces/types/enums/constants have no bodies to drop
      // — or in case of const, the value is small enough to keep)
      outputLines.push(line);
      i++;
      continue;
    }

    // ── Handle non-exported declarations ──
    if (/^(function|const|let|var|class|interface|type|enum)\s+\w+/.test(trimmed) && !line.startsWith('import')) {
      // Non-exported function
      const nonExportFn = /^(async\s+)?function\s+(\w+)\s*\(([^)]*)\)(\s*:\s*(\S+))?\s*{/.exec(trimmed);
      if (nonExportFn) {
        const name = nonExportFn[2];
        const params = nonExportFn[3];
        const returnType = nonExportFn[5] || '';
        const ret = returnType ? `: ${returnType}` : '';
        outputLines.push(`declare function ${name}(${params})${ret};`);

        // Skip body
        braceDepth = 1;
        let j = i + 1;
        while (j < lines.length && braceDepth > 0) {
          const l = lines[j].trim();
          braceDepth += (l.match(/\{/g) || []).length;
          braceDepth -= (l.match(/\}/g) || []).length;
          j++;
        }
        i = j;
        incomplete = true;
        continue;
      }

      // Non-exported const/let/var — keep
      outputLines.push(line);
      i++;
      continue;
    }

    // ── Default: skip lines that are part of dropped bodies ──
    i++;
  }

  const stubContent = [
    '// Generated stub — interface skeleton only, do not edit.',
    '// Original: see source file for full implementation.',
    '// Parser: regex (incomplete)',
    '',
    ...outputLines,
  ].join('\n');

  return { stubContent, incomplete };
}

// ─── Cache management ────────────────────────────────────────────────

/**
 * Read the stub manifest, returning undefined if it doesn't exist yet.
 */
export async function readStubManifest(vaultRoot: string): Promise<StubManifest | undefined> {
  const manifestPath = join(vaultRoot, STUBS_DIR, 'manifest.json');
  if (!existsSync(manifestPath)) {
    return undefined;
  }
  const raw = await readFile(manifestPath, 'utf-8');
  return JSON.parse(raw) as StubManifest;
}

/**
 * Write the stub manifest atomically (write to temp, then rename — simplified: just overwrite).
 */
export async function writeStubManifest(vaultRoot: string, manifest: StubManifest): Promise<void> {
  const manifestPath = join(vaultRoot, STUBS_DIR, 'manifest.json');
  await writeFile(manifestPath, JSON.stringify(manifest, null, 2) + '\n', 'utf-8');
}

/**
 * Check if a manifest entry is still valid by comparing the stored hash with the current source file hash.
 */
export async function isEntryStale(entry: StubManifestEntry, projectRoot: string): Promise<boolean> {
  const sourcePath = join(projectRoot, entry.path);
  if (!existsSync(sourcePath)) {
    return true; // Source file deleted
  }
  const content = await readFile(sourcePath, 'utf-8');
  const currentHash = createHash('sha256').update(content).digest('hex');
  return currentHash !== entry.sha256;
}

/**
 * Compute metadata for a source file: size, mtime, and SHA-256 hash.
 */
export async function computeSourceMetadata(projectRoot: string, projectRelativePath: string): Promise<{
  size: number;
  mtimeMs: number;
  sha256: string;
  content: string;
} | undefined> {
  const absolutePath = join(projectRoot, projectRelativePath);
  if (!existsSync(absolutePath)) {
    return undefined;
  }
  const stats = await stat(absolutePath);
  if (stats.size > MAX_FILE_SIZE) {
    return undefined; // Too large to stub
  }
  const content = await readFile(absolutePath, 'utf-8');
  const hash = createHash('sha256').update(content).digest('hex');
  return {
    size: stats.size,
    mtimeMs: stats.mtimeMs,
    sha256: hash,
    content,
  };
}

// ─── Stub generation ────────────────────────────────────────────────

/**
 * Generate a stub for a single source file.
 * If a valid cached stub exists (same hash), returns without regenerating.
 */
export async function generateStubForFile(
  projectRoot: string,
  vaultRoot: string,
  projectRelativePath: string,
  parser: string = 'regex',
): Promise<GenerateStubResult | undefined> {
  const metadata = await computeSourceMetadata(projectRoot, projectRelativePath);
  if (!metadata) {
    return undefined;
  }

  const { sha256, size, mtimeMs, content } = metadata;
  const ext = extname(projectRelativePath);
  const language = getLanguageForExtension(ext);
  if (!language) {
    return undefined;
  }

  // Check manifest for a valid entry
  const manifest = await readStubManifest(vaultRoot);
  const existingEntry = manifest?.entries.find((e) => e.path === projectRelativePath);

  if (existingEntry && existingEntry.sha256 === sha256 && existingEntry.size === size) {
    // Valid cached stub — nothing to regenerate
    return {
      generated: false,
      stubPath: existingEntry.stubPath,
      incomplete: !!existingEntry.incomplete,
    };
  }

  // Generate stub content
  let stubContent: string;
  let incomplete = false;

  if (language === 'TypeScript' || language === 'JavaScript') {
    const result = generateTypeScriptStub(content);
    stubContent = result.stubContent;
    incomplete = result.incomplete;
  } else {
    // Fallback: metadata-only stub with a comment
    stubContent = [
      `// Stub placeholder — full parsing not yet implemented for ${language}.`,
      `// Source: ${projectRelativePath}`,
      `// Hash: ${sha256}`,
    ].join('\n');
    incomplete = true;
  }

  // Write stub file
  const stubFilename = sanitizeStubPath(projectRelativePath, sha256);
  const stubPathInVault = join(STUBS_DIR, stubFilename);
  const absoluteStubPath = resolve(vaultRoot, stubPathInVault);

  await mkdir(join(vaultRoot, STUBS_DIR), { recursive: true });
  await writeFile(absoluteStubPath, stubContent, 'utf-8');

  // Update manifest
  if (manifest) {
    // Replace existing entry or add new one
    const existingIndex = manifest.entries.findIndex((e) => e.path === projectRelativePath);
    const newEntry: StubManifestEntry = {
      path: projectRelativePath,
      language,
      size,
      mtimeMs,
      sha256,
      stubVersion: 1,
      parser,
      stubPath: stubFilename,
      incomplete,
    };

    if (existingIndex >= 0) {
      manifest.entries[existingIndex] = newEntry;
    } else {
      manifest.entries.push(newEntry);
    }
    manifest.generatedAt = new Date().toISOString();
    await writeStubManifest(vaultRoot, manifest);
  } else {
    // First time — create manifest
    const newManifest: StubManifest = {
      version: 1,
      generatedAt: new Date().toISOString(),
      entries: [{
        path: projectRelativePath,
        language,
        size,
        mtimeMs,
        sha256,
        stubVersion: 1,
        parser,
        stubPath: stubFilename,
        incomplete,
      }],
    };
    await writeStubManifest(vaultRoot, newManifest);
  }

  return {
    generated: true,
    stubPath: stubFilename,
    incomplete,
  };
}

/**
 * Generate stubs for multiple source files at once, reusing the manifest.
 * Used by the context compiler when it needs stubs for indirect dependencies.
 */
export async function generateStubs(
  projectRoot: string,
  vaultRoot: string,
  paths: string[],
  parser: string = 'regex',
): Promise<GenerateStubsResult> {
  const warnings: string[] = [];
  let generated = 0;

  for (const path of paths) {
    try {
      const result = await generateStubForFile(projectRoot, vaultRoot, path, parser);
      if (!result) {
        warnings.push(`Could not generate stub for ${path} (file not found or unsupported language)`);
        continue;
      }
      if (result.generated) {
        generated++;
      }
      if (result.incomplete) {
        warnings.push(`Stub for ${path} is incomplete (parser: ${parser})`);
      }
    } catch (err) {
      warnings.push(`Failed to generate stub for ${path}: ${err instanceof Error ? err.message : String(err)}`);
    }
  }

  const manifest = await readStubManifest(vaultRoot);
  return {
    generated,
    total: manifest?.entries.length ?? 0,
    warnings,
  };
}

/**
 * Initialize the stub cache directory and create an empty manifest.
 * Called during `vault_refresh target=code_stubs` or vault init.
 */
export async function initializeStubCache(vaultRoot: string): Promise<void> {
  const stubsDir = join(vaultRoot, STUBS_DIR);
  await mkdir(stubsDir, { recursive: true });

  const manifestPath = join(stubsDir, 'manifest.json');
  if (!existsSync(manifestPath)) {
    await writeStubManifest(vaultRoot, {
      version: 1,
      generatedAt: new Date().toISOString(),
      entries: [],
    });
  }
}

/**
 * Invalidate a specific stub entry from the manifest and remove its file.
 */
export async function invalidateStub(
  vaultRoot: string,
  projectRelativePath: string,
): Promise<boolean> {
  const manifest = await readStubManifest(vaultRoot);
  if (!manifest) {
    return false;
  }

  const entryIndex = manifest.entries.findIndex((e) => e.path === projectRelativePath);
  if (entryIndex < 0) {
    return false;
  }

  const entry = manifest.entries[entryIndex];
  // Remove the stub file
  const stubAbsolutePath = resolve(vaultRoot, entry.stubPath);
  if (existsSync(stubAbsolutePath)) {
    // Use fs.promises.rm if available, otherwise just delete
    try {
      const { rm } = await import('fs/promises');
      await rm(stubAbsolutePath, { force: true });
    } catch {
      // Ignore deletion errors
    }
  }

  manifest.entries.splice(entryIndex, 1);
  manifest.generatedAt = new Date().toISOString();
  await writeStubManifest(vaultRoot, manifest);
  return true;
}

